f=open('readlead.html','r')
h=f.read()
f.close()
old='function chkCurr(){\nvar val=document.getElementById("curr-in").value.trim();\nvar has=val.length>0;\ndocument.getElementById("curr-badge").style.display=has?"inline-block":"none";\ndocument.getElementById("curr-msg").style.display=has?"block":"none";\nif(has){\ntry{localStorage.setItem("guided_curriculum",val);}catch(e){}\n}\n}\nfunction loadSavedCurriculum(){\ntry{\nvar saved=localStorage.getItem("guided_curriculum");\nif(saved){\nvar el=document.getElementById("curr-in");\nif(el){el.value=saved;chkCurr();}\n}\n}catch(e){}\n}'
new='var currItems=[];\nfunction addCurrItem(val){\ncurrItems.push(val||"");\nrenderCurrItems();\nif(!val)setTimeout(function(){var inputs=document.querySelectorAll(".curr-item-input");inputs[inputs.length-1].focus();},50);\n}\nfunction removeCurrItem(i){\ncurrItems.splice(i,1);\nrenderCurrItems();\nsaveCurr();\n}\nfunction renderCurrItems(){\nvar el=document.getElementById("curr-items");\nif(!currItems.length){el.innerHTML="";return;}\nel.innerHTML=currItems.map(function(v,i){\nreturn"<div style=\'display:flex;gap:6px;margin-bottom:6px\'><input class=\'inp curr-item-input\' value=\'"+v.replace(/\'/g,"&#39;")+"\' placeholder=\'e.g. Reading 1.2: Uses phonics strategies...\' oninput=\'updateCurr("+i+",this.value)\' style=\'flex:1\'/><button onclick=\'removeCurrItem("+i+")\' style=\'background:#FF6B6B;color:#fff;border:none;border-radius:8px;padding:0 10px;font-weight:700;cursor:pointer\'>x</button></div>";\n}).join("");\n}\nfunction updateCurr(i,val){\ncurrItems[i]=val;\nsaveCurr();\n}\nfunction saveCurr(){\nvar joined=currItems.filter(function(v){return v.trim().length>0;}).join("\\n");\ndocument.getElementById("curr-in").value=joined;\nvar has=joined.length>0;\ndocument.getElementById("curr-badge").style.display=has?"inline-block":"none";\ndocument.getElementById("curr-msg").style.display=has?"block":"none";\ntry{localStorage.setItem("guided_curriculum",joined);}catch(e){}\n}\nfunction chkCurr(){saveCurr();}\nfunction loadSavedCurriculum(){\ntry{\nvar saved=localStorage.getItem("guided_curriculum");\nif(saved&&saved.trim()){\ncurrItems=saved.split("\\n").filter(function(l){return l.trim().length>0;});\nrenderCurrItems();\nsaveCurr();\n}\n}catch(e){}\n}'
print('found:',old in h)
h=h.replace(old,new)
open('readlead.html','w').write(h)
print('done')